{% comment %}
Place this in your product template or a Custom Liquid block.
Shows a banner if the product has the tag "shorts".
{% endcomment %}

{% if product.tags contains 'shorts' %}
<style>
  /* —— RC Shorts Bundle (scoped) —— */
  .rc-offer-wrap { margin: 14px 0 18px; }
  .rc-offer {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    border-radius: 12px;
    padding: 14px 16px;
    background: #f8fbff;
  }
  .rc-offer__badge {
    font: 700 14px/1.1 system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
    letter-spacing: .06em;
    text-transform: uppercase;
    padding: 7px 30px;
    border-radius: 3px;
    background: #3D6E2E;
    color: #fff;
    white-space: nowrap;
    margin-bottom: 6px;
  }
  .rc-offer__text {
    display: flex;
    flex-direction: column;
    gap: 2px;
    align-items: center;
  }
  .rc-offer__title {
    margin: 10px 0;
text-transform:uppercase;
    font: 700 20px/1.3 system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
    color: #111;
  }
  .rc-offer__note {
  margin: 0;
  font: 400 12px/2 system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  color: #444;
  letter-spacing: 1px;
}

</style>

<div class="rc-offer-wrap" role="note" aria-label="Shorts bundle offer">
  <div class="rc-offer">
    <span class="rc-offer__badge">Bundle &amp; Save</span>
    <div class="rc-offer__text">
      <p class="rc-offer__title">Buy any 2 shorts,<br>get $20 off</p>
    </div>
  </div>
</div>
{% endif %}

{% assign raw_handles = product.metafields.custom.complete_the_look %}
{% assign look_handles = raw_handles | replace: '"', '' | replace: '[', '' | replace: ']', '' | split: ',' %}

{% if look_handles.size > 0 and look_handles.first != blank %}
  <div class="get-the-look-box">
    <h3 class="get-the-look-heading">GET THE LOOK</h3>
    <div class="get-the-look-grid" id="get-the-look-grid"></div>
  </div>

 <style>
  .get-the-look-box {
    border: 1px solid #eee;
    padding: 20px;
    border-radius: 8px;
    margin-top: 10px;
  }

  .get-the-look-heading {
    font-weight: 700;
    font-size: 16px;
    margin-bottom: 20px;
  }

  .get-the-look-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 16px;
    justify-content: center;
  }

  .get-the-look-grid a {
    flex: 0 1 calc(50% - 16px);
    aspect-ratio: 4 / 5;
    border-radius: 6px;
    overflow: hidden;
    transition: transform 0.2s ease;
  }

  .get-the-look-grid a:hover {
    transform: scale(1.02);
  }

  .get-the-look-grid img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }

</style>



  <script>
    document.addEventListener("DOMContentLoaded", function () {
      const handles = {{ look_handles | json }};
      const grid = document.getElementById("get-the-look-grid");

      handles.forEach(handle => {
        const cleanHandle = handle.trim();
        fetch(`/products/${cleanHandle}.js`)
          .then(response => {
            if (!response.ok) {
              console.error(`Failed to load product for handle: ${cleanHandle}`);
              return null;
            }
            return response.json();
          })
          .then(product => {
            if (!product || !product.images || product.images.length === 0) {
              console.warn("No images found for product:", product);
              return;
            }
            const img = product.images[0];
            const link = document.createElement("a");
            link.href = product.url;
            link.innerHTML = `<img src="${img}" alt="${product.title}" />`;
            grid.appendChild(link);
          })
          .catch(err => console.error("Fetch error:", err));
      });
    });
  </script>
{% endif %}
